/**
 * Shared service utilities — reusable across domain services.
 *
 * SlotManager:  Stateless member-array operations (add, remove, capacity checks)
 * MembershipWorkflow:  Status transition state machine engine
 */
export { DomainEventBus, domainEvents } from './DomainEventBus';
export type {
  DomainEventBase,
  DomainEventMap,
  DomainEventName,
  MemberDiscordLeftPayload,
  MemberDiscordRoleChangedPayload,
  MemberDiscordTimeoutPayload,
  MemberPlatformLeftPayload,
  ModerationActionPayload,
  PrimaryOrgSwitchedPayload,
  RsiOrgJoinedPayload,
  RsiOrgLeftPayload,
  RsiRankChangedPayload,
  RsiSyncFailedPayload,
} from './DomainEventBus';
export {
  ACTIVITY_PARTICIPANT_TRANSITIONS,
  APPLICATION_TRANSITIONS,
  CREW_TRANSITIONS,
  INVITATION_TRANSITIONS,
  JOB_APPLICATION_TRANSITIONS,
  MembershipWorkflow,
  ORG_APPLICATION_TRANSITIONS,
} from './MembershipWorkflow';
export type { Actor, TransitionDef, TransitionMap } from './MembershipWorkflow';
export { SlotManager } from './SlotManager';
export type {
  AddMemberResult,
  RemoveMemberResult,
  RoleSlot,
  SlotCapacity,
  SlotMember,
} from './SlotManager';

